const fs = require('fs');
const args = process.argv.slice(2);
if (args.length < 2) {
  console.error('Usage: node copy.js <source> <destination>');
  process.exit(1);
}
const [source, dest] = args;

fs.readFile(source, 'utf8', (err, data) => {
  if (err) {
    console.error(`Error reading ${source}:`, err.message);
    return;
  }
  fs.writeFile(dest, data, 'utf8', (err) => {
    if (err) {
      console.error(`Error writing to ${dest}:`, err.message);
    } else {
      console.log('File copied successfully.');
    }
  });
});
